const crypto = require('crypto');
const secret = $env.KGANYA_EMBEDDING_WEBHOOK_SECRET;
const headers = $json.headers || {};
const body = $json.body || {};
const signature = headers['x-kganya-signature'] || headers['X-Kganya-Signature'] || '';
const canonical = JSON.stringify(body);
if (secret) {
  const computed = crypto.createHmac('sha256', secret).update(canonical).digest('hex');
  if (computed !== signature) throw new Error('INVALID_SIGNATURE');
}
return [{ json: { signatureValid: true, batchId: headers['x-kganya-batch-id'] || body.batchId || null, checksum: headers['x-kganya-checksum'] || body.checksum || null, body } }];

const input = $json.body || $json;
const jobs = Array.isArray(input.jobs) ? [...input.jobs].sort((a, b) => String(a.jobId).localeCompare(String(b.jobId))) : [];
return [{ json: { batchId: input.batchId, source: input.source || 'kganya', generatedAt: input.generatedAt, jobCount: Number(input.jobCount || jobs.length), jobs, checksum: input.checksum } }];

const batch = $json;
const errors = [];
if (!batch.batchId) errors.push('batchId is required');
if (batch.source !== 'kganya') errors.push('source must be kganya');
if (!batch.generatedAt) errors.push('generatedAt is required');
if (!Number.isInteger(batch.jobCount) || batch.jobCount < 1) errors.push('jobCount must be a positive integer');
if (!Array.isArray(batch.jobs) || batch.jobs.length === 0) errors.push('jobs must be a non-empty array');
if (batch.jobCount !== batch.jobs.length) errors.push('jobCount does not match jobs length');
for (const job of batch.jobs || []) {
  if (!job.jobId) errors.push('jobId is required');
  if (!job.organization?.id) errors.push('organization.id is required');
  if (!job.organization?.clerkOrgId) errors.push('organization.clerkOrgId is required');
  if (!job.knowledgeSource?.id) errors.push('knowledgeSource.id is required');
  if (!job.sourceRecord?.id) errors.push('sourceRecord.id is required');
  if (!job.sourceRecord?.recordKey) errors.push('sourceRecord.recordKey is required');
  if (!Number.isInteger(job.sourceRecord?.version)) errors.push('sourceRecord.version must be an integer');
  if (!job.sourceRecord?.checksum) errors.push('sourceRecord.checksum is required');
}
if (errors.length) throw new Error(`INVALID_BATCH: ${errors.join('; ')}`);
return [{ json: { batchValid: true, batchId: batch.batchId, jobCount: batch.jobCount, normalizedJobs: batch.jobs, checksum: batch.checksum } }];

const queuedCount = Number($node["Queue Ingestion Jobs"].json.queuedCount || 0);
const existingCount = Number($node["Check Batch Idempotency"].json.existingCount || 0);
return [{ json: { batchId: $node["Check Batch Idempotency"].json.batchId || null, received: true, acceptedCount: queuedCount, rejectedCount: 0, duplicateCount: existingCount, queuedCount, completedCount: 0, failedCount: 0, errors: [], checksum: $node["Check Batch Idempotency"].json.checksum || null } }];
